const items = $input.all();
const results = [];

for (const inputData of items) {
  const data = inputData.json.body || inputData.json;
  const properties = Array.isArray(data) ? data : [data];

  for (const item of properties) {
    results.push({
      json: {
        titulo: item.titulo || 'Sin título',
        precio: parseFloat(item.precio) || 0,
        moneda: item.moneda || 'USD',
        url_original: item.link || item.url || '',
        barrio: item.barrio || 'No especificado',
        imagen_principal: item.fotos && item.fotos.length > 0 ? item.fotos[0] : (item.imagen || 'https://www.inmobiliaria.com.uy/images/no-image.jpg'),
        imagenes: JSON.stringify(item.fotos || []),
        descripcion: item.descripcion || '',
        tipo_operacion: item.tipo_operacion || 'alquiler',
        es_dueno_directo: !!item.es_dueno_directo,
        num_fotos: item.fotos ? item.fotos.length : (item.imagen ? 1 : 0),
        fuente: 'meli_hunter_local_pro'
      }
    });
  }
}

return results;

const results = [];
for (const item of $input.all()) {
  // Rescatar los datos limpios originales (o los de DB si RETURNING * funcionó)
  const data = $('Limpiar Datos').item.json || item.json;

  let mensaje = `<a href="${data.imagen_principal || ''}">&#8205;</a>\n`;
  mensaje += data.es_dueno_directo ? '🥷 <b>¡ALERTA DUEÑO DIRECTO!</b> 🔥\n\n' : '🏠 <b>NUEVA PROPIEDAD DETECTADA</b>\n\n';
  mensaje += `🏷️ <b>${data.titulo || 'Sin título'}</b>\n`;
  mensaje += `💰 ${data.moneda || 'USD'} ${data.precio || 0}\n`;
  mensaje += `📍 ${data.barrio || 'Sin ubicación'}\n`;
  mensaje += `──────────────────\n`;
  mensaje += `🔗 <a href="${data.url_original || ''}">Enlace Oficial</a>\n`;
  if (data.num_fotos) mensaje += `\n📸 Total capturadas: ${data.num_fotos} fotos.`;

  results.push({
    json: {
      ...data,
      mensaje_telegram: mensaje
    }
  });
}
return results;
